 1	import React, { FC, MouseEvent, useState } from 'react';
 2	
 3	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  WORKLOADS,
 7	  WORKLOADS_DESCRIPTIONS,
 8	  WORKLOADS_LABELS,
 9	} from '@kubevirt-utils/resources/template';
10	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
11	import { Form, FormGroup } from '@patternfly/react-core';
12	import { SelectOption } from '@patternfly/react-core';
13	
14	import FormPFSelect from '../FormPFSelect/FormPFSelect';
15	
16	type WorkloadProfileModalProps = {
17	  initialWorkload: WORKLOADS;
18	  isOpen: boolean;
19	  onClose: () => void;
20	  onSubmit: (workload: WORKLOADS) => Promise<K8sResourceCommon | void>;
21	};
22	
23	const WorkloadProfileModal: FC<WorkloadProfileModalProps> = ({
24	  initialWorkload,
25	  isOpen,
26	  onClose,
27	  onSubmit,
28	}) => {
29	  const { t } = useKubevirtTranslation();
30	  const [workload, setWorkload] = useState<WORKLOADS>(initialWorkload || WORKLOADS.desktop);
31	
32	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: WORKLOADS) => {
33	    event.preventDefault();
34	    setWorkload(value);
35	  };
36	
37	  return (
38	    <TabModal
39	      headerText={t('Edit workload profile')}
40	      isOpen={isOpen}
41	      onClose={onClose}
42	      onSubmit={() => onSubmit(workload)}
43	    >
44	      <Form>
45	        <FormGroup fieldId="template-firmware-bootloader" label={t('Workload profile')}>
46	          <FormPFSelect
47	            onSelect={handleChange}
48	            selected={workload}
49	            selectedLabel={WORKLOADS_LABELS[workload]}
50	            toggleProps={{ isFullWidth: true }}
51	          >
52	            {Object.entries(WORKLOADS_LABELS).map(([key, value]) => (
53	              <SelectOption description={t(WORKLOADS_DESCRIPTIONS[key])} key={key} value={key}>
54	                {value}
55	              </SelectOption>
56	            ))}
57	          </FormPFSelect>
58	        </FormGroup>
59	      </Form>
60	    </TabModal>
61	  );
62	};
63	
64	export default WorkloadProfileModal;

